const express = require('express');
const mongoose = require('mongoose');

const app = express();

// Connect to MongoDB
mongoose.connect('mongodb://localhost/mydatabase', { useNewUrlParser: true });

// Define a schema for our data model
const mySchema = new mongoose.Schema({
  name: String,
  age: Number,
  email: String
});

// Create a model using the schema
const MyModel = mongoose.model('MyModel', mySchema);

app.get('/search', (req, res) => {
  // Get search filters from request query parameters
  const filters = req.query;

  // Use MongoDB operators to create a find() query
  const query = MyModel.find(filters);

  // Execute the query and return the results
  query.exec((err, data) => {
    if (err) {
      res.status(500).send({ message: 'Error executing query' });
    } else {
      res.json(data);
    }
  });
});

